	(1684,820,'_oembed_b87b85a77eee2639a4a8e7532051da32','<iframe src=\"http://player.vimeo.com/video/19553725\" width=\"640\" height=\"360\" frameborder=\"0\"></iframe>'),
	(1663,821,'_feedback_author','Steve Shay'),
	(1664,821,'_feedback_author_email','steveinmilford@yahoo.com'),
	(1665,821,'_feedback_author_url',''),
	(1666,821,'_feedback_subject','[Goodbye Picasso] Contact'),
	(1667,821,'_feedback_ip','24.102.170.178'),
	(1668,821,'_feedback_all_fields','a:4:{s:4:\"Name\";s:10:\"Steve Shay\";s:5:\"Email\";s:24:\"steveinmilford@yahoo.com\";s:7:\"Website\";s:0:\"\";s:7:\"Message\";s:788:\"We drove down from Milford PA (about 2 hours) to hear Spirit Family Reunion (who we\'d heard up here at a Music Festival 2 years ago, and who were performing right after your set).  We got there early and were INCREDIBLY happy we did.  What a great sound -- we\'re glad we bought the CD last night too.  You guys are going to go VERY far -- it will be nice to see you break through to the big time someday (I\'m thinking sooner than later).  If you ever would consider doing a private party (maybe) up here in Milford PA, shoot me an email.  If not, I think you\'re definitely worth seeing again and again -- even if NYC is two hours away (it\'s still where I grew-up).\r\n\r\nPowerful performance, poetic excellence, and the crazy eyes are a perfect performance.  WOW!\r\n\r\nSteve Shay\r\n570-296-3730\";}'),
	(1669,821,'_feedback_extra_fields','a:0:{}'),
	(1670,821,'_feedback_akismet_values','a:63:{s:14:\"comment_author\";s:10:\"Steve Shay\";s:20:\"comment_author_email\";s:24:\"steveinmilford@yahoo.com\";s:18:\"comment_author_url\";s:0:\"\";s:20:\"contact_form_subject\";s:25:\"[Goodbye Picasso] Contact\";s:17:\"comment_author_IP\";s:14:\"24.102.170.178\";s:15:\"comment_content\";s:788:\"We drove down from Milford PA (about 2 hours) to hear Spirit Family Reunion (who we\'d heard up here at a Music Festival 2 years ago, and who were performing right after your set).  We got there early and were INCREDIBLY happy we did.  What a great sound -- we\'re glad we bought the CD last night too.  You guys are going to go VERY far -- it will be nice to see you break through to the big time someday (I\'m thinking sooner than later).  If you ever would consider doing a private party (maybe) up here in Milford PA, shoot me an email.  If not, I think you\'re definitely worth seeing again and again -- even if NYC is two hours away (it\'s still where I grew-up).\r\n\r\nPowerful performance, poetic excellence, and the crazy eyes are a perfect performance.  WOW!\r\n\r\nSteve Shay\r\n570-296-3730\";s:12:\"comment_type\";s:12:\"contact_form\";s:7:\"user_ip\";s:14:\"24.102.170.178\";s:10:\"user_agent\";s:176:\"Mozilla/4.0 (compatible; MSIE 8.0; Windows NT 6.1; WOW64; Trident/4.0; GTB6.6; SLCC2; .NET CLR 2.0.50727; .NET CLR 3.5.30729; .NET CLR 3.0.30729; Media Center PC 6.0; .NET4.0C)\";s:8:\"referrer\";s:34:\"http://goodbyepicasso.com/contact/\";s:4:\"blog\";s:25:\"http://goodbyepicasso.com\";s:15:\"SERVER_SOFTWARE\";s:6:\"Apache\";s:11:\"REQUEST_URI\";s:9:\"/contact/\";s:14:\"CONTENT_LENGTH\";s:3:\"991\";s:12:\"CONTENT_TYPE\";s:33:\"application/x-www-form-urlencoded\";s:7:\"DBENTRY\";s:145:\"/kunden/homepages/34/d204322993/htdocs/goodbyepicasso:d0000#CPU 8 #MEM 10240 #CGI 350 #NPROC 16 #TAID 45125295 #WERB 0 #LANG 3 #PARKING 1 #STAT 1\";s:13:\"DOCUMENT_ROOT\";s:53:\"/kunden/homepages/34/d204322993/htdocs/goodbyepicasso\";s:11:\"HTTP_ACCEP