	(1900,833,'_feedback_akismet_values','a:61:{s:14:\"comment_author\";s:5:\"Galen\";s:20:\"comment_author_email\";s:20:\"gsmith@kindlewood.co\";s:18:\"comment_author_url\";s:21:\"http://kindlewood.co/\";s:20:\"contact_form_subject\";s:25:\"[Goodbye Picasso] Contact\";s:17:\"comment_author_IP\";s:14:\"173.73.127.222\";s:15:\"comment_content\";s:486:\"Hey Goodbye Picasso, \r\n\r\nOur band has an opportunity to work with Sylvia Harris from Record Label Door. She has you listed on her website as one of her clients/success stories. Would you mind sharing with me what your experience has been with Sylvia? We try our best to do thorough reference checks before paying any money out to anyone and would appreciate any help you can offer. Rest assured, whatever you share would remain confidential.\r\n\r\nThank you for your time.\r\n\r\nBest, \r\nGalen\";s:12:\"comment_type\";s:12:\"contact_form\";s:7:\"user_ip\";s:14:\"173.73.127.222\";s:10:\"user_agent\";s:70:\"Mozilla/5.0 (Windows NT 6.0; WOW64; rv:5.0) Gecko/20100101 Firefox/5.0\";s:8:\"referrer\";s:34:\"http://goodbyepicasso.com/contact/\";s:4:\"blog\";s:25:\"http://goodbyepicasso.com\";s:15:\"SERVER_SOFTWARE\";s:6:\"Apache\";s:11:\"REQUEST_URI\";s:9:\"/contact/\";s:14:\"CONTENT_LENGTH\";s:3:\"687\";s:12:\"CONTENT_TYPE\";s:33:\"application/x-www-form-urlencoded\";s:7:\"DBENTRY\";s:145:\"/kunden/homepages/34/d204322993/htdocs/goodbyepicasso:d0000#CPU 8 #MEM 10240 #CGI 350 #NPROC 16 #TAID 45125295 #WERB 0 #LANG 3 #PARKING 1 #STAT 1\";s:13:\"DOCUMENT_ROOT\";s:53:\"/kunden/homepages/34/d204322993/htdocs/goodbyepicasso\";s:11:\"HTTP_ACCEPT\";s:63:\"text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8\";s:19:\"HTTP_ACCEPT_CHARSET\";s:30:\"ISO-8859-1,utf-8;q=0.7,*;q=0.7\";s:20:\"HTTP_ACCEPT_ENCODING\";s:13:\"gzip, deflate\";s:20:\"HTTP_ACCEPT_LANGUAGE\";s:14:\"en-us,en;q=0.5\";s:15:\"HTTP_CONNECTION\";s:10:\"keep-alive\";s:9:\"HTTP_HOST\";s:18:\"goodbyepicasso.com\";s:12:\"HTTP_REFERER\";s:34:\"http://goodbyepicasso.com